def load_settings(defaults: dict, file_settings: dict, cli_settings: dict) -> dict:
    # Собираем настройки с соблюдением приоритета:
    # defaults < file_settings < cli_settings (без None) < APP_PORT env var
    merged = {**defaults, **file_settings}

    for key, value in cli_settings.items():
        if value is not None:
            merged[key] = value

    if "APP_PORT" in os.environ:
        merged["port"] = int(os.environ["APP_PORT"])

    return merged

